import React, { useEffect, useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";

export default function AddTravel({ employee }) {
  const [form, setForm] = useState({
    travel_date: "",
    purpose: "",
    amount: "",
    location_from: "",
    location_to: "",
  });

  const [history, setHistory] = useState([]);
  const [filterMonth, setFilterMonth] = useState("");

  useEffect(() => {
    fetchHistory();
  }, [filterMonth]);

  async function fetchHistory() {
    let url = `${apiBase}/travel-expenses?emp=${employee.employee_id}`;

    if (filterMonth) url += `&month=${filterMonth}`;

    const res = await fetch(url);
    const data = await res.json();
    setHistory(data);
  }

  async function addTravel(e) {
    e.preventDefault();

    const res = await fetch(`${apiBase}/travel-expenses`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ employee_id: employee.employee_id, ...form }),
    });

    const data = await res.json();
    if (data.success) {
      alert("Travel expense added!");
      fetchHistory();
    }
  }

  async function deleteTravel(id) {
    if (!window.confirm("Delete this record?")) return;

    await fetch(`${apiBase}/travel-expenses/${id}`, { method: "DELETE" });
    fetchHistory();
  }

  return (
    <div style={{ padding: 30, fontFamily: "Segoe UI" }}>
      <h2 style={{ color: "#0f9d58" }}>🚌 Travel Expense</h2>

      {/* FILTER */}
      <div style={{ marginBottom: 15 }}>
        <label>Select Month: </label>
        <input
          type="month"
          value={filterMonth}
          onChange={(e) => setFilterMonth(e.target.value)}
        />
      </div>

      {/* FORM */}
      <form onSubmit={addTravel} style={formBox}>
        <input
          type="date"
          required
          value={form.travel_date}
          onChange={(e) => setForm({ ...form, travel_date: e.target.value })}
        />
        <input
          placeholder="Purpose"
          required
          value={form.purpose}
          onChange={(e) => setForm({ ...form, purpose: e.target.value })}
        />
        <input
          type="number"
          placeholder="Amount"
          required
          value={form.amount}
          onChange={(e) => setForm({ ...form, amount: e.target.value })}
        />

        <input
          placeholder="From"
          value={form.location_from}
          onChange={(e) => setForm({ ...form, location_from: e.target.value })}
        />

        <input
          placeholder="To"
          value={form.location_to}
          onChange={(e) => setForm({ ...form, location_to: e.target.value })}
        />

        <button style={btn}>Submit</button>
      </form>

      {/* HISTORY TABLE */}
      <h3 style={{ marginTop: 30 }}>History</h3>

      <table style={tableStyle}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>Amount</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {history.map((t) => (
            <tr key={t.travel_id}>
              <td>{t.travel_date}</td>
              <td>{t.purpose}</td>
              <td>₹{t.amount}</td>
              <td>
                <button onClick={() => deleteTravel(t.travel_id)}>❌</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

const formBox = {
  background: "#fff",
  padding: 20,
  borderRadius: 10,
  display: "flex",
  flexDirection: "column",
  gap: 10,
  width: 350,
};

const btn = {
  background: "#0f9d58",
  padding: 10,
  border: "none",
  color: "white",
  borderRadius: 6,
};

const tableStyle = {
  width: "100%",
  marginTop: 20,
  borderCollapse: "collapse",
};
